def render_page(title, content_template, **kwargs):
    """Render a page with the base template."""
    kwargs['current_user'] = get_current_user()
    content = render_template_string(content_template, **kwargs)
    return render_template_string(BASE_TEMPLATE, title=title, content=content,
                                  current_user=kwargs['current_user'])


# --- Routes ---

@app.route('/')
def home():
    return render_page('Home', HOME_TEMPLATE)


@app.route('/register', methods=['GET', 'POST'])
def register():
    if get_current_user():
        return redirect(url_for('dashboard'))

    if request.method == 'POST':
        username = request.form.get('username', '').strip()
        password = request.form.get('password', '')
        confirm_password = request.form.get('confirm_password', '')

        if not username or not password:
            flash('Username and password are required.', 'error')
        elif len(username) < 3:
            flash('Username must be at least 3 characters.', 'error')
        elif len(password) < 6:
            flash('Password must be at least 6 characters.', 'error')
        elif password != confirm_password:
            flash('Passwords do not match.', 'error')
        else:
            success, message = register_user(username, password)
            if success:
                flash(message + ' Please log in.', 'success')
                return redirect(url_for('login'))
            else:
                flash(message, 'error')

    return render_page('Register', REGISTER_TEMPLATE)


@app.route('/login', methods=['GET', 'POST'])
def login():
    if get_current_user():
        return redirect(url_for('dashboard'))

    if request.method == 'POST':
        username = request.form.get('username', '').strip()
        password = request.form.get('password', '')
        remember = request.form.get('remember') == 'on'

        if not username or not password:
            flash('Username and password are required.', 'error')
        elif authenticate_user(username, password):
            session_id = create_session(username)

            if remember:
                # Extend session lifetime to 30 days
                app.permanent_session_lifetime = 30 * 24 * 3600
                if session_id in active_sessions:
                    active_sessions[session_id]['remember'] = True

            flash('Logged in successfully!', 'success')

            next_url = request.args.get('next')
            if next_url:
                return redirect(next_url)
            return redirect(url_for('dashboard'))
        else:
            flash('Invalid username or password.', 'error')

    return render_page('Login', LOGIN_TEMPLATE)


@app.route('/logout')
def logout():
    destroy_session()
    flash('You have been logged out.', 'success')
    return redirect(url_for('home'))


@app.route('/dashboard')
@login_required
def dashboard():
    session_id = session.get('session_id', '')
    session_data = active_sessions.get(session_id, {})

    login_time = time.strftime('%Y-%m-%d %H:%M:%S',
                               time.localtime(session_data.get('login_time', 0)))
    last_activity = time.strftime('%Y-%m-%d %H:%M:%S',
                                  time.localtime(session_data.get('last_activity', 0)))
    ip_address = session_data.get('ip_address', 'Unknown')

    return render_page('Dashboard', DASHBOARD_TEMPLATE,
                       session_id=session_id,
                       login_time=login_time,
                       last_activity=last_activity,
                       ip_address=ip_address)


@app.route('/profile', methods=['GET', 'POST'])
@login_required
def profile():
    username = get_current_user()

    if request.method == 'POST':
        current_password = request.form.get('current_password', '')
        new_password = request.form.get('new_password', '')
        confirm_password = request.form.get('confirm_password', '')

        if not authenticate_user(username, current_password):
            flash('Current password is incorrect.', 'error')
        elif len(new_password) < 6:
            flash('New password must be at least 6 characters.', 'error')
        elif new_password != confirm_password:
            flash('New passwords do not match.', 'error')
        else:
            salt, hashed = hash_password(new_password)
            users_db[username]['salt'] = salt
            users_db[username]['password_hash'] = hashed
            flash('Password changed successfully!', 'success')

    user_data = users_db.get(username, {})
    created_at = time.strftime('%Y-%m-%d %H:%M:%S',
                               time.localtime(user_data.get('created_at', 0)))

    # Count active sessions for this user
    session_count = sum(1 for s in active_sessions.values() if s['username'] == username)

    return render_page('Profile', PROFILE_TEMPLATE,
                       created_at=created_at,
                       session_count=session_count)


@app.route('/sessions', methods=['GET', 'POST'])
@login_required
def sessions_view():
    username = get_current_user()
    current_session_id = session.get('session_id', '')

    if request.method == 'POST':
        revoke_all = request.form.get('revoke_all')
        target_session_id = request.form.get('session_id')

        if revoke_all:
            # Revoke all sessions except current
            to_remove = [sid for sid, sdata in active_sessions.items()
                         if sdata['username'] == username and sid != current_session_id]
            for sid in to_remove:
                del active_sessions[sid]
            flash('All other sessions have been revoked.', 'success')
        elif target_session_id and target_session_id in active_sessions:
            if active_sessions[target_session_id]['username'] == username:
                del active_sessions[target_session_id]
                flash('Session revoked successfully.', 'success')

    # Get all sessions for this user
    user_sessions = []
    for sid, sdata in active_sessions.items():
        if sdata['username'] == username:
            sdata_copy = dict(sdata)
            sdata_copy['login_time_formatted'] = time.strftime(
                '%Y-%m-%d %H:%M:%S', time.localtime(sdata['login_time']))
            sdata_copy['last_activity_formatted'] = time.strftime(
                '%Y-%m-%d %H:%M:%S', time.localtime(sdata['last_activity']))
            user_sessions.append((sid, sdata_copy))

    return render_page('Sessions', SESSIONS_TEMPLATE,
                       sessions=user_sessions,
                       current_session_id=current_session_id)


@app.before_request
def cleanup_expired_sessions():
    """Periodically clean up expired sessions."""
    current_time = time.time()
    expired = [sid for sid, sdata in active_sessions.items()
               if current_time - sdata['last_activity'] > app.config['PERMANENT_SESSION_LIFETIME']]
    for sid in expired:
        del active_sessions[sid]


